@js:
// 定义所有视频源
var sources = [
 `{{@@source.0@src}}`, 
 `{{@@source.1@src}}`,
 `{{@@source.2@src}}`,
];

// 生成源按钮 - 只生成非空源的按钮
var sourceButtons = "";
var validSources = []; // 存储有效源的索引

// 收集所有非空的有效源
for (var i = 0; i < sources.length; i++) {
    // 检查源是否为空（去除空格后判断）
    if (sources[i] && sources[i].trim() !== '') {
        validSources.push(i);
    }
}

// 只有当有效源数量大于1时才显示按钮
if (validSources.length > 1) {
    for (var j = 0; j < validSources.length; j++) {
        var index = validSources[j];
        sourceButtons += `<button class="source-btn" data-index="${index}">源${index+1}</button>`;
    }
}

