result=`
<html><head><meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1,minimum-scale=1,maximum-scale=1,user-scalable=no" />

  <style>html, body {text-align: center;margin: 0; padding: 0;width: 100%;overflow: hidden;} </style>
  <script src="https://unpkg.com/hls.js@1.4.3/dist/hls.min.js"></script>
</head><body>
  <div class="container">
    <div class="title">{{@@script@all##"vod_name":"(.*)","vod_actor##$1##}}</div>
    <video id="video" width="100%" height="91%" poster="${java.get('pic')}" controls autoplay muted loop></video>
  </div>
<script>
const v=document.getElementById('video'),s=[
  "${result}",
  "${result}"];
let c=0;
function setupCustomControls(e){/* 自定义功能实现 */}
function playNext(){
  c>=s.length&&(c=0); // 循环重置计数器
  const u=s[c++];

  // 检测Hls对象是否存在
  if (typeof Hls !== 'undefined' && Hls.isSupported()) {
    const h=new Hls();
    h.loadSource(u);
    h.attachMedia(v);
    h.on(Hls.Events.MANIFEST_PARSED,()=>v.play().then(()=>setupCustomControls(v)).catch(console.log));
    h.on(Hls.Events.ERROR,(_,d)=>d.fatal&&playNext())
  } else { // Hls加载失败或浏览器原生支持HLS
    if (v.canPlayType('application/vnd.apple.mpegurl')) {
      v.src = u;
      v.onloadedmetadata = () => v.play().then(() => setupCustomControls(v));
      v.onerror = playNext;
    } else {
      // 如果都不支持，尝试直接播放（可能支持MP4等格式）
      v.src = u;
      v.onerror = playNext;
      v.play().then(() => setupCustomControls(v)).catch(playNext);
    }
  }
}playNext();
</script>
</body></html>
`

