<script>
(function() {
// 配置解密参数
const key = CryptoJS.enc.Latin1.parse('9q4h7kt7skwsc9af1qmwy14jkfq2biab');
const iv = CryptoJS.enc.Latin1.parse('6b3gslw69k6eazmw');
const encryptedUrl = "${result}"; // 注入加密URL

try {
// 1. 预处理URL
let base64Str = encryptedUrl
.replace(/-/g, '+') // URL安全Base64替换
.replace(/_/g, '/');

// 2. Base64补全
const pad = base64Str.length % 4;
if (pad) base64Str += '===='.slice(0, 4 - pad);

// 3. 解密流程
const encryptedData = CryptoJS.enc.Base64.parse(base64Str);
const decrypted = CryptoJS.AES.decrypt(
{ ciphertext: encryptedData },
key,
{ iv: iv, mode: CryptoJS.mode.CBC, padding: CryptoJS.pad.ZeroPadding }
);

// 4. 处理解密结果
const decryptedStr = decodeURIComponent(
CryptoJS.enc.Latin1.stringify(decrypted)
);
const parts = decryptedStr.split(',');

if (parts.length !== 5) throw new Error('无效解密数据');
const realUrl = \`https://cdn-m.asujp.com:59888/f/\${parts[0]}/\${parts[1]}/\${parts[2]}/play.m3u8?_KS=\${parts[3]}&_KE=\${parts[4]}\`;

// 5. 动态设置视频源
document.getElementById('video').src = realUrl;
} catch (e) {
document.body.innerHTML = '视频解析失败: ' + e.message;
}
})();
</script>
</body>
</html>
`;
