.container {
    position: relative; /* 相对定位，用于包含视频 */
    height: 100%; /* 容器高度与视频原始高度相同 */
    overflow: hidden; /* 隐藏超出容器的部分 */
}
.title {
    position: absolute; /* 绝对定位，相对于容器 */
    top: 0; 
    width: 100%;
    overflow: hidden; 
    text-overflow: ellipsis;
    display: -webkit-box;
    -webkit-box-orient: vertical; 
    -webkit-line-clamp: 2;
    z-index: 1; /* 确保标题在视频之上 */
    background: #000; /* 纯黑色背景 */ 
    padding: 0 0 3px 0;
}
video {
    position: absolute; /* 绝对定位，相对于容器 */ 
    top: -20px; /* 视频上移 */
    left: 0; 
    width: 100%; 
    height: calc(96% + 20px);  /* 调整高度以适应内容 */
    object-fit: contain; /* 确保视频内容不被裁剪 */
    z-index: 0; /* 确保视频在标题之下 */
    controls="controls" autoplay muted; 
}

coverDecodeJs:
function decodeImage(data, key) {
  var out = new Packages.java.io.ByteArrayOutputStream();

  // 读取前9个字节进行异或解密，后面的字节直接写入
  for (var i = 0; i < 9; i++) {
    var byte = data.read();
    if (byte == -1) break; // 如果数据长度不足9字节，提前结束
    out.write(byte ^ key);
  }

  // 处理剩余的字节（如果有的话）
  var remainingByte;
  while ((remainingByte = data.read()) != -1) {
    out.write(remainingByte);
  }

  return out.toByteArray();
}

function toByteArray(input) {
  var out = new Packages.java.io.ByteArrayOutputStream()
  var buffer = java.strToBytes('\0'.repeat(4096))
  var bytesRead
  while ((bytesRead = input.read(buffer)) != -1) {
    out.write(buffer, 0, bytesRead)
  }
  return out.toByteArray()
}

if (src.endsWith('.gif')) {
  toByteArray(result)
} else {
  decodeImage(result, 0x12); // 使用0x12作为密钥，与前端保持一致
}

